import React, { useState } from "react"
import { Card, Input, Typography, Popover, message, Avatar } from "antd"
import { MoreOutlined } from "@ant-design/icons"
import ButtonCustom from "src/components/MyButton/Button"
import CommentService from "src/services/CommentService"
import notice from "src/components/Notice"
import SvgIcon from "src/components/SvgIcon"

const { Text } = Typography
const { TextArea } = Input

export default function CommentSection({
  AssociationId,
  commentList,
  onNewComment,
  isLogin,
  getComment,
}) {
  const [isEditing, setIsEditing] = useState(false)
  const [editCommentId, setEditCommentId] = useState(null)
  const [editContent, setEditContent] = useState("")
  const [commentContent, setCommentContent] = useState("")
  const [loading, setLoading] = useState(false)
  const [loadingComment, setLoadingComment] = useState(false)
  const createComment = async () => {
    try {
      setLoading(true)
      const payload = {
        Content: commentContent,
        TargetID: AssociationId,
        TargetType: 0,
      }
      const res = await CommentService.CreateComments(payload)
      if (res && !res.isError) {
        notice({ msg: "Bình luận thành công", isSuccess: true })
        onNewComment(res.Object)
        setCommentContent("")
      } else {
        message.error(res?.Object || "Đã xảy ra lỗi khi gửi bình luận.")
      }
    } catch (err) {
      console.error(err)
      notice({ msg: "Không thể gửi bình luận", isSuccess: false })
    } finally {
      setLoading(false)
    }
  }

  const deleteComments = async id => {
    setLoading(true)
    try {
      const res = await CommentService.DeleteComments({ commentId: id })
      if (res?.isOK || !res?.isError) {
        notice({ msg: "Xóa bình luận thành công", isSuccess: true })
        onNewComment(prev => prev.filter(c => c.CommentId !== id))
      } else {
        notice({ msg: "Xóa bình luận không thành công", isSuccess: false })
      }
    } catch (error) {
      console.error("Can not delete this comment", error)
      message.error("Lỗi khi xoá bình luận.")
    } finally {
      setLoading(false)
    }
  }

  const handleStartEdit = comment => {
    setIsEditing(true)
    setEditCommentId(comment.CommentId)
    setEditContent(comment.Content)
  }

  const handleCancelEdit = () => {
    setIsEditing(false)
    setEditCommentId(null)
    setEditContent("")
  }

  const handleUpdateComment = async () => {
    if (!editContent.trim()) {
      message.warning("Nội dung không được để trống.")
      return
    }

    setLoading(true)
    try {
      const res = await CommentService.UpdateComments({
        commentId: editCommentId,
        Content: editContent,
      })
      if (!res.isError) {
        notice({ msg: "Cập nhật bình luận thành công", isSuccess: true })
        setIsEditing(false)
        setEditCommentId(null)
        setEditContent("")
        onNewComment()
      } else {
        message.error(res.Object || "Lỗi khi cập nhật bình luận.")
      }
    } catch (error) {
      console.error("Update comment failed", error)
      message.error("Không thể cập nhật bình luận.")
    } finally {
      setLoading(false)
    }
  }

  const handleLikeComment = async commentId => {
    if (!isLogin) {
      notice({ msg: "Bạn cần đăng nhập để thích bình luận.", isSuccess: false })
      return
    }
    setLoadingComment(true)
    try {
      const res = await CommentService.LikeComments({ commentId })
      if (res?.isOk || !res?.isError) {
        if (getComment) {
          getComment()
        } else {
          onNewComment()
        }
      } else {
        message.error("Không thể like bình luận.")
      }
    } catch (err) {
      console.error("Like comment failed", err)
      message.error("Lỗi khi thực hiện thao tác.")
    } finally {
      setLoadingComment(false)
    }
  }

  return (
    <div className="comment-section">
      <Card className="comment-card">
        <div className="title-comment">Bình Luận</div>
        <TextArea
          rows={1}
          placeholder="Viết bình luận..."
          value={commentContent}
          onChange={e => setCommentContent(e.target.value)}
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault()
              createComment()
            }
          }}
          className="comment-input mt-10"
        />

        <div className="mt-3">
          {commentList?.length === 0 ? (
            <Text type="secondary">Chưa có bình luận nào.</Text>
          ) : (
            commentList.map(comment => (
              <div key={comment.CommentId} className="comment-item">
                <div className="wrapper">
                  <div className="comment-header">
                    <Avatar
                      src={comment.UserAvatar}
                      alt="avatar"
                      className="comment-avatar"
                    />
                    <div className="comment-meta">
                      <div>
                        <span className="comment-text">
                          <Text strong className="comment-author">
                            {comment.UserFullName}
                          </Text>
                          <span>: {comment.Content}</span>
                        </span>
                      </div>

                      <div className="comment-time">
                        {comment.TimeExistence}
                      </div>

                      <div className="social-option">
                        <div
                          className="d-flex"
                          style={{ cursor: "pointer", alignItems: "center" }}
                          onClick={() => handleLikeComment(comment.CommentId)}
                        >
                          <SvgIcon
                            name={comment.IsLike ? "liked" : "react-like-fb"}
                            style={{ marginRight: "5px" }}
                          />
                          <div>{comment.NumberLike}</div>
                        </div>
                      </div>
                    </div>
                  </div>
                  <div>
                    <Popover
                      placement="bottomRight"
                      trigger="hover"
                      content={
                        <div className="comment-popover">
                          <ButtonCustom
                            onClick={() => handleStartEdit(comment)}
                          >
                            Chỉnh sửa
                          </ButtonCustom>
                          <ButtonCustom
                            onClick={() => deleteComments(comment.CommentId)}
                          >
                            Xoá
                          </ButtonCustom>
                        </div>
                      }
                    >
                      <MoreOutlined className="more-icon" />
                    </Popover>
                  </div>
                </div>

                {/* Social actions */}

                {/* Nếu đang chỉnh sửa đúng comment này */}
                {isEditing && editCommentId === comment.CommentId && (
                  <>
                    <TextArea
                      rows={2}
                      value={editContent}
                      onChange={e => setEditContent(e.target.value)}
                      className="edit-input"
                    />
                    <div className="edit-actions">
                      <ButtonCustom
                        type="primary"
                        size="small"
                        onClick={handleUpdateComment}
                      >
                        Lưu
                      </ButtonCustom>
                      <ButtonCustom
                        type="default"
                        size="small"
                        onClick={handleCancelEdit}
                      >
                        Huỷ
                      </ButtonCustom>
                    </div>
                  </>
                )}
              </div>
            ))
          )}
        </div>
      </Card>
    </div>
  )
}
