import React, { useState, useEffect } from "react"
import { Card, Spin, Alert, Collapse } from "antd"
import AssociationService from "src/services/AssociationService"
import ROUTER from "src/router/ROUTER"
import { useNavigate } from "react-router-dom"
import defaultLogo from "src/assets/images/logo/logo_mac_dinh.png"
export default function GroupChild({ parentId }) {
  const navigate = useNavigate()
  const [all, setAll] = useState([])
  const [children, setChildren] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const isValidAssociation = (item, parentId = null) => {
    const excludedStatus = [2, 4, 5]
    const isStatusValid = !excludedStatus.includes(item?.Status)
    const isParentMatch = parentId !== null ? item?.ParentID === parentId : true
    return isStatusValid && isParentMatch
  }
  useEffect(() => {
    setLoading(true)
    AssociationService.getAssociationListNoAuthor()
      .then(res => {
        const list = res.Object || []
        const filtered = list.filter(item => isValidAssociation(item))
        setAll(filtered)
      })
      .catch(err => {
        console.error(err)
        setError("Không lấy được danh sách hội")
      })
      .finally(() => setLoading(false))
  }, [])

  useEffect(() => {
    if (!parentId) return setChildren([])
    setChildren(all.filter(item => isValidAssociation(item, parentId)))
  }, [parentId, all])
  return (
    <Collapse>
      <div className="group-child">
        <div className="ml-10 mr-10">
          <div className="slider-container">
            {children.map(child => (
              <Card
                key={child.AssociationID}
                hoverable
                bordered={false}
                className="card-custom"
                bodyStyle={{ padding: 16 }}
              >
                <div style={{ display: "flex", alignItems: "flex-start" }}>
                  <div className="thumbnail">
                    {child.Image ? (
                      <img src={child.Image} alt={child.AssociationName} />
                    ) : (
                      <img srC={defaultLogo} />
                    )}
                  </div>
                  <div className="info">
                    <div
                      className="title max-line1"
                      onClick={() =>
                        navigate(ROUTER.HOI_NHOM_CHI_TIET(child.AssociationID))
                      }
                    >
                      {child.AssociationName}
                    </div>
                  </div>
                </div>
                <div className="info mt-14">
                  <div className="field">
                    <strong>Số lượng:</strong> {child.MemberNo ?? "—"} hội viên
                  </div>
                </div>
              </Card>
            ))}
          </div>
        </div>
      </div>
    </Collapse>
  )
}
