import http from "../01_axios"
import {
  apiCreate,
  apiGetAllComments,
  apiLikeComments,
  apiDeleteComments,
  apiUpdateComments,
} from "./urls"

const CreateComments = data => http.post(apiCreate, data)
const GetAllComments = params => http.get(apiGetAllComments, { params })
const LikeComments = ({ commentId }) =>
  http.put(apiLikeComments, null, { params: { commentId } })

const DeleteComments = ({ commentId }) =>
  http.delete(apiDeleteComments, { params: { commentId } })
const UpdateComments = params => http.put(apiUpdateComments, null, { params })

const CommentService = {
  CreateComments,
  GetAllComments,
  LikeComments,
  DeleteComments,
  UpdateComments,
}
export default CommentService
