import { Breadcrumb, Button, Col, message, Modal, Row, Typography } from "antd"
import { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import { useNavigate, useParams } from "react-router-dom"
import defaultLogo from "src/assets/images/logo/logo_mac_dinh.png"
import LayoutCommon from "src/components/Common/LayoutCommon"
import ButtonCustom from "src/components/MyButton/Button"
import SpinCustom from "src/components/SpinCustom"
import SvgIcon from "src/components/SvgIcon"
import TitleCustom from "src/components/TitleCustom"
import { SYSTEM_KEY } from "src/constants/constants"
import STORAGE, { getStorage } from "src/lib/storage"
import { getListComboByKey } from "src/lib/utils"
import ROUTER from "src/router/ROUTER"
import AssociationService from "src/services/AssociationService"
import CommentService from "src/services/CommentService"
import MemberService from "src/services/MemberService"
import "../style.scss"
import CommentSection from "./CommentSection"
import GroupChild from "./GroupChild"
import RelateGroup from "./RelateGroup"
import notice from "src/components/Notice"
const { Text } = Typography

export default function GroupListDetail() {
  const { id } = useParams()
  const isLogin = getStorage(STORAGE.TOKEN)
  const navigate = useNavigate()
  const [details, setDetails] = useState(null)
  const [loading, setLoading] = useState(false)
  const [commnetList, setCommentList] = useState([])
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const typeList = useMemo(
    () => getListComboByKey(SYSTEM_KEY.ASSOCIATION_TYPE, listSystemKey) || [],
    [listSystemKey],
  )
  const fetchComments = async () => {
    try {
      const res = await CommentService.GetAllComments({
        targetId: id,
        targetType: 0,
        sortType: 1,
      })
      setCommentList(res.Object.data)
    } catch (error) {
      message.error("Không thể tải bình luận")
    }
  }

  const handleJoinAssociation = async AssociationID => {
    try {
      const body = { AssociationID }
      const response = await MemberService.joinAssociationRequest(body)

      if (response?.isError) return
      notice({
        msg: "Đăng ký thành công. Vui lòng chờ xác thực từ quản trị viên.",
      })
    } catch (error) {
      console.error("Lỗi khi đăng ký hội nhóm:", error)
      message.error("Có lỗi xảy ra, vui lòng thử lại sau.")
    }
  }

  const confirmJoinAssociation = AssociationID => {
    Modal.confirm({
      title: "Xác nhận đăng ký hội nhóm",
      content: "Bạn có chắc chắn muốn đăng ký tham gia hội nhóm này?",
      okText: "Đăng ký",
      cancelText: "Hủy",
      onOk: () => handleJoinAssociation(AssociationID),
    })
  }

  useEffect(() => {
    if (id) fetchComments()
  }, [id])
  const statusList = useMemo(
    () => getListComboByKey(SYSTEM_KEY.STATUS, listSystemKey) || [],
    [listSystemKey],
  )
  useEffect(() => {
    if (!id) return
    setLoading(true)
    AssociationService.getAssociationDetail({ AssociationID: id })
      .then(res => {
        if (!res.isError && res.Object) setDetails(res.Object)
        else setDetails(null)
      })
      .catch(() => setDetails(null))
      .finally(() => setLoading(false))
  }, [id])

  const typeDescription = useMemo(
    () =>
      typeList.find(item => item.CodeValue === details?.AssociationType)
        ?.Description || "Không xác định",
    [details, typeList],
  )

  if (loading) {
    return <SpinCustom loading={loading} />
  }

  if (!details) {
    return (
      <div style={{ textAlign: "center", color: "#999", padding: 60 }}>
        <Text type="secondary">Không tìm thấy hội nhóm.</Text>
      </div>
    )
  }

  return (
    <div className="group-list-detail">
      <LayoutCommon>
        <Breadcrumb style={{ marginBottom: 16 , marginTop: 16}}>
          <Breadcrumb.Item onClick={() => navigate(ROUTER.DANH_SACH_HOI_NHOM)}>
            <SvgIcon name="back">Quay Lại</SvgIcon>
          </Breadcrumb.Item>
          <Breadcrumb.Item>Chi tiết hội nhóm</Breadcrumb.Item>
        </Breadcrumb>

        <Row gutter={24}>
          <Col xs={24} lg={16}>
            <div className="association-header">
              <div className="avatar-circle">
                <img src={details.Image || defaultLogo} alt="Avatar" />
              </div>
              <div className="association-d-flex-column">
                <div className="association-title">
                  <div className="name">{details.AssociationName}</div>
                </div>
                <div className="summary mt-5 mb-50">
                  <p>
                    {details.AssociationName} là chi hội tiềm năng mang đến nhiều lợi ích cho
                    cộng đồng
                  </p>
                </div>
                <div className="association-card-buttons">
                  <div className="btn-register">
                    <ButtonCustom
                      onClick={() =>
                        confirmJoinAssociation(details.AssociationID)
                      }
                    >
                      Đăng Ký Tham Gia
                    </ButtonCustom>
                  </div>
                  <div className="favourite">
                    <Button>Yêu Thích</Button>
                  </div>
                  <div className="share">
                    <Button>Chia sẻ</Button>
                  </div>
                </div>
              </div>
            </div>
            <div className="info-grid mt-30">
              <div className="infor-title">Thông Tin Chi Tiết</div>
              <div></div>
              <div className="info-item">
                <span className="label">Mã hội</span>
                <span className="value">{details.AssociationCode}</span>
              </div>
              <div className="info-item">
                <span className="label">Ngày thành lập</span>
                <span className="value">
                  {details.EstablishmentDate
                    ? new Date(details.EstablishmentDate).toLocaleDateString()
                    : "—"}
                </span>
              </div>
              <div className="info-item">
                <span className="label">Địa chỉ</span>
                <span className="value">{details.Address || "—"}</span>
              </div>
              <div className="info-item">
                <span className="label">Loại hội</span>
                <span className="value">{typeDescription}</span>
              </div>
              <div className="info-item">
                <span className="label">Số điện thoại</span>
                <span className="value">{details.PhoneNumber || "—"}</span>
              </div>

              <div className="info-item">
                <span className="label">Email</span>
                <span className="value">{details.Email || "—"}</span>
              </div>
              <div className="info-item">
                <span className="label">Số hội viên</span>
                <span className="value">{details.MemberNo ?? "—"}</span>
              </div>
            </div>

            <div className="mt-30">
              <TitleCustom level={3}>Các nhóm nhỏ</TitleCustom>
              <div className="horizontal-scroll ">
                <GroupChild parentId={id} />
              </div>
            </div>
            {/* <div className="mt-40">
              <CommentSection
                commentList={commnetList}
                AssociationId={id}
                onNewComment={fetchComments}
                isLogin={isLogin}
              />
            </div> */}
          </Col>
          <Col xs={24} lg={8} style={{marginTop: '-60px'}}>
            <TitleCustom>Các nhóm liên quan</TitleCustom>
            <RelateGroup />
          </Col>
        </Row>
      </LayoutCommon>
    </div>
  )
}
