import { useEffect, useState } from "react"
import { useNavigate } from "react-router-dom"
import ROUTER from "src/router/ROUTER"
import AssociationService from "src/services/AssociationService"
import defaultLogo from "src/assets/images/logo/logo_mac_dinh.png"
import "./RelateGroup.scss"
import { Col, Row } from "antd"

const RelateGroup = () => {
  const [associations, setAssociations] = useState([])
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate()

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true)
        const response = await AssociationService.getAssociationListNoAuthor()
        const list = response?.Object ?? []
        const filteredList = Array.isArray(list)
          ? list.filter(item => ![2, 4, 5].includes(item.Status))
          : []
        setAssociations(filteredList)
      } catch (error) {
        console.error("Lỗi khi getAssociationNameList:", error)
        setAssociations([])
      } finally {
        setLoading(false)
      }
    }
    fetchData()
  }, [])

  return (
    <div className="relate-group">
      <div className="wrapper">
        {associations.map(item => (
          <div key={item.AssociationID} className="relate-group-card">
            <Row gutter={16} align="middle">
              {/* Cột trái - ảnh */}
              <Col xs={8} sm={6} md={6} lg={6}>
                <div className="relate-group-avatar">
                  <img
                    src={item.Image || defaultLogo}
                    alt={item.AssociationName}
                  />
                </div>
              </Col>

              {/* Cột phải - tên + số hội viên */}
              <Col xs={16} sm={18} md={18} lg={18}>
                <div className="relate-group-body">
                  <h3
                    className="relate-group-title"
                    onClick={() =>
                      navigate(ROUTER.HOI_NHOM_CHI_TIET(item.AssociationID))
                    }
                  >
                    {item.AssociationName}
                  </h3>
                  <p className="relate-group-members">
                    Số hội viên: {item.MemberNo ?? "—"}
                  </p>
                </div>
              </Col>
            </Row>
          </div>
        ))}
      </div>
    </div>
  )
}

export default RelateGroup
